var e=[{id:`L2_1`,type:`dialog`,speaker:`SNIPER_ESPR_BUNNY_NULL`,text:{KOREA:`평생 책임져 준다는 식의 그런 말, 아무한테나 쉽게 하면 못 써.`,JPN:`一生責任を取るなんてこと、誰かれ構わず言っちゃダメよ。`,ENG:`You shouldn’t talk so lightly about taking care of someone for the rest of time.`,TWN:`我會照顧你一輩子這種話是不能隨便亂說的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_ESPR_BUNNY_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SNIPER_ESPR_BUNNY_NULL`,text:{KOREA:`후훗, 그러니까 이제부터는 괜찮은 상대인지 아닌지 내가 잘 살펴보고 얘기해 줄게. 알겠지, 귀염둥이?`,JPN:` ふふっ。だからこれからはいい相手かどうか私がちゃんと見極めてあげるわ。わかったわね？　かわい子ちゃん。`,ENG:` Fu fuu, so from now on... I’ll take a good look at your partners and see if they suit you. Understood, cutie?`,TWN:`呵呵，現在開始我會親自驗證你是不是一個可靠的對象，知道嗎，小可愛？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_ESPR_BUNNY_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};